// Allergens in bit-position order.
// Index 0 → bit 0 (value 1), index 7 → bit 7 (value 128).
const ALLERGENS = [
  "eggs",         // 1
  "peanuts",      // 2
  "shellfish",    // 4
  "strawberries", // 8
  "tomatoes",     // 16
  "chocolate",    // 32
  "pollen",       // 64
  "cats",         // 128
] as const;

export type Allergen = (typeof ALLERGENS)[number];

// ─── Approach 1: Lazy bitmask ────────────────────────────────────────────────
//
// Compute `1 << index` on every call.
// Simple and has zero up-front cost.
// indexOf is O(n) but n=8, so it doesn't matter in practice.
//
// When to prefer: one-off scripts, tiny datasets, you want minimal indirection.

export function isAllergicTo_lazy(score: number, allergen: Allergen): boolean {
  const idx = ALLERGENS.indexOf(allergen);
  return (score & (1 << idx)) !== 0;
}

export function allergies_lazy(score: number): Allergen[] {
  return ALLERGENS.filter((_, idx) => (score & (1 << idx)) !== 0);
}

// ─── Approach 2: Pre-built lookup ────────────────────────────────────────────
//
// Build a Map<Allergen, bitmask> once at module load.
// Each call is a single O(1) Map.get() instead of a linear search.
// Slightly more memory; pays off if called in a hot loop.
//
// When to prefer: library code, hot paths, or when unknown strings are possible
// (Map.get returns undefined gracefully; indexOf returns -1 and shifts wrong).

const ALLERGEN_BITS = new Map<Allergen, number>(
  ALLERGENS.map((name, i) => [name, 1 << i])
);

export function isAllergicTo(score: number, allergen: Allergen): boolean {
  return (score & (ALLERGEN_BITS.get(allergen) ?? 0)) !== 0;
}

export function allergies(score: number): Allergen[] {
  return ALLERGENS.filter((a) => (score & ALLERGEN_BITS.get(a)!) !== 0);
}

import { describe, test, expect } from "bun:test";
import {
  isAllergicTo,
  isAllergicTo_lazy,
  allergies,
  allergies_lazy,
  type Allergen,
} from "./allergies";

