  describe(`isAllergicTo — ${impl.label}`, () => {
    test("score 0 → not allergic to anything", () => {
      expect(impl.isAllergicTo(0, "eggs")).toBe(false);
      expect(impl.isAllergicTo(0, "cats")).toBe(false);
    });

    test("single bit matches exactly one allergen", () => {
      expect(impl.isAllergicTo(1,   "eggs")).toBe(true);
      expect(impl.isAllergicTo(1,   "peanuts")).toBe(false);
      expect(impl.isAllergicTo(2,   "peanuts")).toBe(true);
      expect(impl.isAllergicTo(128, "cats")).toBe(true);
      expect(impl.isAllergicTo(128, "eggs")).toBe(false);
    });

    test("score 255 → allergic to all", () => {
      const all: Allergen[] = [
        "eggs", "peanuts", "shellfish", "strawberries",
        "tomatoes", "chocolate", "pollen", "cats",
      ];
      for (const a of all) expect(impl.isAllergicTo(255, a)).toBe(true);
    });

    test("high bits beyond 128 are ignored", () => {
