    test("score 0 → empty list", () => {
      expect(impl.allergies(0)).toEqual([]);
    });

    test("single allergen", () => {
      expect(impl.allergies(1)).toEqual(["eggs"]);
      expect(impl.allergies(2)).toEqual(["peanuts"]);
      expect(impl.allergies(128)).toEqual(["cats"]);
    });

    test("multiple allergens returned in bit-position order", () => {
      expect(impl.allergies(3)).toEqual(["eggs", "peanuts"]);  // bits 0+1
      expect(impl.allergies(34)).toEqual(["peanuts", "chocolate"]); // bits 1+5
    });

    test("score 255 → all eight allergens", () => {
      expect(impl.allergies(255)).toEqual([
        "eggs", "peanuts", "shellfish", "strawberries",
        "tomatoes", "chocolate", "pollen", "cats",
      ]);
    });

    test("high bits ignored", () => {
      expect(impl.allergies(257)).toEqual(["eggs"]); // 256 + 1
    });
  });
}

